import React, { useRef } from 'react';

interface ChatInputProps {
  input: string;
  setInput: (val: string) => void;
  attachments: { name: string; type: string; data: string }[];
  setAttachments: React.Dispatch<React.SetStateAction<{ name: string; type: string; data: string }[]>>;
  isProcessing: boolean;
  onSubmit: (overrideInput?: string, subMode?: 'branch' | 'chat') => void;
  onStop: () => void;
  editingNodeId: string | null;
  onPaste: (e: React.ClipboardEvent) => void;
}

export const ChatInput: React.FC<ChatInputProps> = ({
  input,
  setInput,
  attachments,
  setAttachments,
  isProcessing,
  onSubmit,
  onStop,
  editingNodeId,
  onPaste,
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      Array.from(e.target.files).forEach((file: File) => {
        const reader = new FileReader();
        reader.onload = (ev) => {
          if (ev.target?.result) {
            setAttachments((prev) => [
              ...prev,
              { name: file.name, type: file.type, data: ev.target!.result as string },
            ]);
          }
        };
        reader.readAsDataURL(file);
      });
      e.target.value = '';
    }
  };

  return (
    <div className="absolute bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-200 p-4 z-30 shadow-2xl">
      <div className="max-w-4xl mx-auto">
        {attachments.length > 0 && (
          <div className="flex gap-2 mb-3 overflow-x-auto py-1">
            {attachments.map((att, i) => (
              <div key={i} className="relative group shrink-0">
                <div className="h-14 w-14 rounded-xl border-2 border-slate-100 overflow-hidden shadow-sm">
                  {att.type.startsWith('image/') ? (
                    <img src={att.data} className="h-full w-full object-cover" />
                  ) : (
                    <div className="h-full w-full bg-slate-50 flex items-center justify-center text-[10px] font-bold">
                      FILE
                    </div>
                  )}
                </div>
                <button
                  onClick={() => setAttachments((prev) => prev.filter((_, idx) => idx !== i))}
                  className="absolute -top-1 -right-1 bg-white rounded-full p-0.5 text-slate-400 hover:text-red-500 shadow-sm border border-slate-200 opacity-0 group-hover:opacity-100 transition-all"
                >
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>
            ))}
          </div>
        )}

        <div className="relative flex items-end gap-2 bg-slate-50 p-2 rounded-2xl border border-slate-200 shadow-inner focus-within:ring-2 focus-within:ring-indigo-100 transition-all">
          <button
            onClick={() => fileInputRef.current?.click()}
            className="p-2.5 text-slate-400 hover:text-indigo-600 hover:bg-white rounded-xl transition-all"
            title="Attach images"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"
              />
            </svg>
          </button>
          <input type="file" multiple accept="image/*" ref={fileInputRef} className="hidden" onChange={handleFileChange} />

          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                onSubmit(undefined, e.ctrlKey || e.metaKey ? 'branch' : 'chat');
              }
            }}
            onPaste={onPaste}
            placeholder={editingNodeId ? 'Refine this node...' : 'Type a message to Gemini...'}
            className="flex-1 bg-transparent border-none focus:ring-0 resize-none py-3 px-2 text-sm max-h-32 min-h-[44px]"
            rows={1}
            style={{ height: 'auto', minHeight: '44px' }}
          />

          <div className="flex flex-col gap-1 pb-1">
            <button
              onClick={isProcessing ? onStop : () => onSubmit(undefined, 'chat')}
              disabled={!isProcessing && !input.trim() && attachments.length === 0}
              className={`p-2 rounded-xl transition-all shadow-md ${
                isProcessing
                  ? 'bg-white text-red-500 border-2 border-red-100 hover:border-red-200 hover:bg-red-50'
                  : 'bg-indigo-600 text-white hover:bg-indigo-700 disabled:opacity-50 shadow-indigo-200'
              }`}
              title={isProcessing ? 'Stop Generation' : 'Send (Continue Chat)'}
            >
              {isProcessing ? (
                <svg className="w-5 h-5 animate-pulse" fill="currentColor" viewBox="0 0 24 24">
                  <path d="M6 6h12v12H6z" />
                </svg>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 12h14M12 5l7 7-7 7" />
                </svg>
              )}
            </button>
          </div>
        </div>
        <div className="text-[10px] text-slate-400 text-center mt-2 font-medium">
          <b>Enter</b> to chat • <b>Ctrl+Enter</b> to branch history
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { format } from 'date-fns';
import { ProjectNode } from '../../types';

interface NodeHeaderProps {
  node: ProjectNode;
  parentNode?: ProjectNode;
  allNodes: ProjectNode[];
  currentIndex: number;
  isSidebarOpen: boolean;
  onToggleSidebar: () => void;
  onSelectNode: (id: string) => void;
  onShowDebug: () => void;
  onShowDataExplorer: () => void;
  onRegenerate: () => void;
  onRefresh: () => void;
  onShowSynthesisModal: () => void;
  onShowCleanupModal: () => void;
  onUndoCleanup?: () => void;
  hasDebugError: boolean;
  activeProjectDataLength: number;
}

export const NodeHeader: React.FC<NodeHeaderProps> = ({
  node,
  parentNode,
  allNodes,
  currentIndex,
  isSidebarOpen,
  onToggleSidebar,
  onSelectNode,
  onShowDebug,
  onShowDataExplorer,
  onRegenerate,
  onRefresh,
  onShowSynthesisModal,
  onShowCleanupModal,
  onUndoCleanup,
  hasDebugError,
  activeProjectDataLength,
}) => {
  const hasPrev = currentIndex > 0;
  const hasNext = currentIndex < allNodes.length - 1;

  return (
    <div className="shrink-0 h-16 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 flex items-center justify-between z-10">
      <div className="flex items-center gap-4 min-w-0">
        {!isSidebarOpen && (
          <button
            onClick={onToggleSidebar}
            className="p-2 -ml-2 hover:bg-slate-100 rounded-lg text-slate-500 transition-colors border border-transparent hover:border-slate-100"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 6h16M4 12h16M4 18h7" />
            </svg>
          </button>
        )}

        <div className="flex items-center gap-2">
          <button
            disabled={!hasPrev}
            onClick={() => onSelectNode(allNodes[currentIndex - 1].id)}
            className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400 disabled:opacity-20 transition-colors"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          <button
            disabled={!hasNext}
            onClick={() => onSelectNode(allNodes[currentIndex + 1].id)}
            className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400 disabled:opacity-20 transition-colors"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" />
            </svg>
          </button>
        </div>

        <div className="min-w-0 border-l border-slate-200 pl-4 ml-2">
          <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase tracking-widest">
            {parentNode ? (
              <span
                className="cursor-pointer hover:text-indigo-600 truncate max-w-[120px]"
                onClick={() => onSelectNode(parentNode.id)}
              >
                {parentNode.visualization?.title || 'Parent'}
              </span>
            ) : (
              <span>Root</span>
            )}
            <span>/</span>
            <span className="shrink-0">{format(new Date(node.timestamp), 'MMM d, HH:mm')}</span>
          </div>
          <div className="flex items-center gap-2 overflow-hidden">
            <h1 className="text-sm font-bold text-slate-900 leading-none mt-1 truncate max-w-md">
              {node.visualization?.title || 'Untitled Node'}
            </h1>

            {node.debugInfo && (
              <button
                onClick={onShowDebug}
                className={`ml-1 p-1 rounded-full transition-all shrink-0 ${
                  hasDebugError
                    ? 'bg-red-100 text-red-600 hover:bg-red-200 animate-pulse'
                    : 'bg-slate-100 text-slate-400 hover:bg-slate-200 hover:text-slate-600'
                }`}
                title="Debug Inspector"
              >
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" />
                </svg>
              </button>
            )}
          </div>
        </div>
      </div>

      <div className="flex gap-2 shrink-0">
        {activeProjectDataLength > 0 && (
          <button
            onClick={onShowDataExplorer}
            className="px-3 py-1.5 bg-white border border-slate-200 text-slate-600 text-[10px] font-bold rounded-lg hover:border-indigo-300 hover:text-indigo-600 transition-all shadow-sm flex items-center gap-2"
            title="Open Data Store Explorer"
          >
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M4 7v10c0 2.21 3.582 4 8 4s8-1.79 8-4V7M4 7c0 2.21 3.582 4 8 4s8-1.79 8-4M4 7c0-2.21 3.582-4 8-4s8 1.79 8 4m0 5c0 2.21-3.582 4-8 4s-8-1.79-8-4"
              />
            </svg>
            Data
            <span className="bg-slate-100 px-1.5 py-0.5 rounded-full text-[9px] text-slate-500">
              {activeProjectDataLength}
            </span>
          </button>
        )}

        <div className="w-px h-6 bg-slate-200 mx-1 self-center"></div>

        <button
          onClick={onRegenerate}
          className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
          title="Regenerate from input"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"
            />
          </svg>
        </button>
        <button
          onClick={onRefresh}
          className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
          title="Re-analyze context & update project data"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"
            />
          </svg>
        </button>

        {node.restorePoint && onUndoCleanup ? (
          <button
            onClick={onUndoCleanup}
            className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all flex items-center gap-1.5"
            title="Undo Cleanup (Restore previous state)"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" />
            </svg>
          </button>
        ) : (
          <button
            onClick={onShowCleanupModal}
            className="p-2 text-slate-400 hover:text-purple-600 hover:bg-purple-50 rounded-lg transition-all"
            title="Consolidate chat history into a single turn"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"
              />
            </svg>
          </button>
        )}

        <div className="w-px h-6 bg-slate-200 mx-1 self-center"></div>
        <button
          onClick={onShowSynthesisModal}
          className="px-3 py-1.5 bg-slate-900 text-white text-[10px] font-bold rounded-lg hover:bg-slate-800 transition-all shadow-sm"
        >
          Synthesize Child
        </button>
      </div>
    </div>
  );
};

import React from 'react';

interface SnapshotBannerProps {
  currentIndex: number;
  totalSteps: number;
  hasPrevSnapshot: boolean;
  hasNextSnapshot: boolean;
  onPrevSnapshot: () => void;
  onNextSnapshot: () => void;
  onRevert: () => void;
  onExit: () => void;
}

export const SnapshotBanner: React.FC<SnapshotBannerProps> = ({
  currentIndex,
  totalSteps,
  hasPrevSnapshot,
  hasNextSnapshot,
  onPrevSnapshot,
  onNextSnapshot,
  onRevert,
  onExit,
}) => {
  return (
    <div className="bg-indigo-600 text-white px-6 py-2 flex items-center justify-between text-xs shadow-md z-30 transition-all">
      <div className="flex items-center gap-3">
        <svg className="w-4 h-4 animate-pulse shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
        </svg>
        <div>
          <span className="font-bold block">Viewing Historical Snapshot</span>
          <span className="opacity-70 text-[10px]">
            Turn {currentIndex + 1} of {totalSteps}
          </span>
        </div>
      </div>

      <div className="flex items-center gap-3">
        <div className="flex items-center bg-indigo-700/50 rounded-lg p-0.5 border border-indigo-500/50">
          <button
            onClick={onPrevSnapshot}
            disabled={!hasPrevSnapshot}
            className="p-1.5 hover:bg-indigo-600 rounded-md disabled:opacity-30 disabled:hover:bg-transparent transition-colors"
            title="Previous Snapshot"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          <div className="w-px h-3 bg-indigo-500/50 mx-1"></div>
          <button
            onClick={onNextSnapshot}
            disabled={!hasNextSnapshot}
            className="p-1.5 hover:bg-indigo-600 rounded-md disabled:opacity-30 disabled:hover:bg-transparent transition-colors"
            title="Next Snapshot (or Latest)"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" />
            </svg>
          </button>
        </div>

        <div className="w-px h-4 bg-indigo-500/50 mx-1"></div>

        <button
          onClick={onRevert}
          className="bg-white/10 hover:bg-red-500/80 px-3 py-1.5 rounded-lg font-bold transition-colors flex items-center gap-2 border border-white/10 hover:border-red-400"
          title="Revert current state to this snapshot (Truncates future chat)"
        >
          <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" />
          </svg>
          Restore this State
        </button>

        <button
          onClick={onExit}
          className="bg-white/10 hover:bg-white/20 px-3 py-1.5 rounded-lg font-bold transition-colors flex items-center gap-2 border border-white/10"
        >
          Exit View
          <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </div>
    </div>
  );
};

import React from 'react';
import { ModelProvider, ThinkingBudgetLevel, CustomModelConfig, ProjectState } from '../../types';

